cat > /tmp/inspect.cs << 'EOF'
using System;
using System.Reflection;
using Microsoft.VisualStudio.TestTools.UnitTesting;

var type = typeof(TestMethodAttribute);
Console.WriteLine($"Type: {type.FullName}");
Console.WriteLine($"IsSealed: {type.IsSealed}");
Console.WriteLine($"BaseType: {type.BaseType?.FullName}");
Console.WriteLine();

Console.WriteLine("Methods:");
foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
{
    Console.WriteLine($"  {(m.IsVirtual ? "virtual " : "")}{m.ReturnType.Name} {m.Name}({string.Join(", ", Array.ConvertAll(m.GetParameters(), p => p.ParameterType.Name + " " + p.Name))})");
}

Console.WriteLine();
Console.WriteLine("Looking for TestTimeout...");
var asm = type.Assembly;
foreach (var t in asm.GetTypes())
{
    if (t.Name.Contains("TestTimeout") || t.Name.Contains("Timeout"))
    {
        Console.WriteLine($"  Found: {t.FullName}");
    }
}

Console.WriteLine();
Console.WriteLine("TimeoutAttribute constructors:");
var timeoutType = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.TimeoutAttribute");
if (timeoutType != null)
{
    foreach (var c in timeoutType.GetConstructors())
    {
        Console.WriteLine($"  ({string.Join(", ", Array.ConvertAll(c.GetParameters(), p => p.ParameterType.Name + " " + p.Name))})");
    }
    foreach (var p in timeoutType.GetProperties())
    {
        Console.WriteLine($"  Property: {p.PropertyType.Name} {p.Name}");
    }
}
EOF

